for tx in block.body().transactions() {
    if tx.is_scheduled() || tx.is_async_commitment() || tx.is_async_settlement() { continue; }
    if origin_tx_hashes.contains(&tx.hash()) { continue; }
    let sender = precomputed_sender.or_else(|| tx.recover_signer())?;
    tx_sender_pairs.push((*tx.hash(), sender));
}

let state_db = StateProviderDatabase::new(state_provider);
let mut db = State::builder().with_database(state_db).with_bundle_update().build();
let pending_counts = batch_sender_pending_job_counts(&mut db, None, &senders_vec)?;
let unlocked_senders = batch_senders_all_phase1_settled(&mut db, None, &locked_senders, block_number)?;

let existing_jobs = batch_jobs_exist(&mut db, None, &tx_hashes_to_check)?;
for (tx_hash, sender) in locked_tx_sender_pairs {
    if !existing_jobs.contains(&tx_hash) {
        return Err(BlockVerificationError::SenderLockedInAsyncPool { tx_hash, sender });
    }
}
